7526 static Instruction *foldICmpOfVectorReduce(ICmpInst &I, const DataLayout &DL,
7527                                            IRBuilderBase &Builder) {
7528   if (!ICmpInst::isEquality(I.getPredicate()))
7529     return nullptr;
7530 
7531   // The caller puts constants after non-constants.
7532   Value *Op = I.getOperand(0);
7533   Value *Const = I.getOperand(1);
7534 
7535   // For Cond an equality condition, fold
7536   //
7537   //   icmp (eq|ne) (vreduce_(or|and) Op), (Zero|AllOnes) ->
7538   //   icmp (eq|ne) Op, (Zero|AllOnes)
7539   //
7540   // with a bitcast.
7541   Value *Vec;
7542   if ((match(Const, m_ZeroInt()) &&
7543        match(Op, m_OneUse(m_Intrinsic<Intrinsic::vector_reduce_or>(
7544                      m_Value(Vec))))) ||
7545       (match(Const, m_AllOnes()) &&
7546        match(Op, m_OneUse(m_Intrinsic<Intrinsic::vector_reduce_and>(
7547                      m_Value(Vec)))))) {
7548     auto *VecTy = dyn_cast<FixedVectorType>(Vec->getType());
7549     if (!VecTy)
7550       return nullptr;
7551     Type *VecEltTy = VecTy->getElementType();
7552     unsigned ScalarBW =
7553         DL.getTypeSizeInBits(VecEltTy) * VecTy->getNumElements();
7554     if (!DL.fitsInLegalInteger(ScalarBW))
7555       return nullptr;
7556     Type *ScalarTy = IntegerType::get(I.getContext(), ScalarBW);
7557     Value *NewConst = match(Const, m_ZeroInt())
7558                           ? ConstantInt::get(ScalarTy, 0)
7559                           : ConstantInt::getAllOnesValue(ScalarTy);
7560     return CmpInst::Create(Instruction::ICmp, I.getPredicate(),
7561                            Builder.CreateBitCast(Vec, ScalarTy), NewConst);
7562   }
7563   return nullptr;
