7732 Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
7733   bool Changed = false;
7734   const SimplifyQuery Q = SQ.getWithInstruction(&I);
7735   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
7736   unsigned Op0Cplxity = getComplexity(Op0);
7737   unsigned Op1Cplxity = getComplexity(Op1);
7738 
7739   /// Orders the operands of the compare so that they are listed from most
7740   /// complex to least complex.  This puts constants before unary operators,
7741   /// before binary operators.
7742   if (Op0Cplxity < Op1Cplxity) {
7743     I.swapOperands();
7744     std::swap(Op0, Op1);
7745     Changed = true;
7746   }
7747 
7748   if (Value *V = simplifyICmpInst(I.getCmpPredicate(), Op0, Op1, Q))
7749     return replaceInstUsesWith(I, V);
7750 
7751   // Comparing -val or val with non-zero is the same as just comparing val
7752   // ie, abs(val) != 0 -> val != 0
7753   if (I.getPredicate() == ICmpInst::ICMP_NE && match(Op1, m_Zero())) {
7754     Value *Cond, *SelectTrue, *SelectFalse;
7755     if (match(Op0, m_Select(m_Value(Cond), m_Value(SelectTrue),
7756                             m_Value(SelectFalse)))) {
7757       if (Value *V = dyn_castNegVal(SelectTrue)) {
7758         if (V == SelectFalse)
7759           return CmpInst::Create(Instruction::ICmp, I.getPredicate(), V, Op1);
7760       } else if (Value *V = dyn_castNegVal(SelectFalse)) {
7761         if (V == SelectTrue)
7762           return CmpInst::Create(Instruction::ICmp, I.getPredicate(), V, Op1);
7763       }
7764     }
